def test_no_d_small_m():
    p = mpz(
        7478755670255767435237487693415479182290330775502792675052667363676831056436638619069277770540533350723045234676443621124912287506103439704868369839725279
    )
    q = mpz(
        9232828888049557325429111621080998490274442347556398052322580869768941301413255711626092627273543579067597113958627672298942570149816938335701615759283713
    )
    e = mpz(65537)
    c = mpz(
        
    )

    n = p * q
    phi = (p - mpz(1)) * (q - mpz(1))
    x = gcd(e, phi)

    m = no_d_small_m(n, phi, e, x, c)
    assert m is not None
    plaintext = long_to_bytes(int(m)).decode()
    assert "NSSCTF" in plaintext


