def test_rabin():
    p = mpz(
        67711062621608175960173275013534737889372437946924512522469843485353704013203
    )
    q = mpz(
        91200252033239924238625443698357031288749612243099728355449192607988117291739
    )
    c = mpz(
        5251890478898826530186837207902117236305266861227697352434308106457554098811792713226801824100629792962861125855696719512180887415808454466978721678349614
    )

    m1, m2, m3, m4 = rabin(p, q, c)
    results = [long_to_bytes(int(m)).decode(errors="replace") for m in [m1, m2, m3, m4]]
    assert any("NSSCTF" in r for r in results)


def test_wiener_small_d():
    n = mpz(
        6969872410035233098344189258766624225446081814953480897731644163180991292913719910322241873463164232700368119465476508174863062276659958418657253738005689
    )
    e = mpz(
        3331016607237504021038095412236348385663413736904453330557803644384818257225138777641344877202234881627514102078530507171735156112302207979925588113589669
    )
    c = mpz(
        1754994938947260364311041300467524420957926989584983693004487724099773647229373820465164193428679197813476633649362998772470084452129370353136199193923837
    )

    d = wiener(n, e)
    assert d is not None

    m = powmod(c, d, n)
    plaintext = long_to_bytes(int(m)).decode()
    assert "NSSCTF" in plaintext


